mapper.select:
SELECT HOUR(create_time) as hour, COUNT(*) as count FROM user_action_log WHERE action_type = 'VIEW_DETAIL'
AND user_id = #{userId}
GROUP BY hour

SELECT DATE_FORMAT(create_time, '%Y-%m-%d') as dateStr, COUNT(CASE WHEN action_type = 'VIEW_DETAIL' THEN 1 END) as viewCount, COUNT(CASE WHEN action_type = 'FAVORITE' THEN 1 END) as favoriteCount, COUNT(CASE WHEN action_type = 'SEARCH' THEN 1 END) as searchCount, -- 假设 CLICK_TRIP 代表预订跳转 COUNT(CASE WHEN action_type = 'CLICK_TRIP' THEN 1 END) as bookingCount FROM user_action_log
AND user_id = #{userId} AND create_time BETWEEN #{beginTime} AND #{endTime}
GROUP BY dateStr ORDER BY dateStr ASC

select action_type,count(*) as count  from user_action_log

    AND user_id = #{userId}

group by action_type

SELECT show_price FROM user_action_log

    AND user_id = #{userId}
    AND action_type = 'VIEW_DETAIL'
    AND comment_score IS NOT NULL
    AND comment_score >= #{minScore}
    AND comment_score < #{maxScore}
    AND show_price IS NOT NULL
